import { serve } from "https://deno.land/std@0.208.0/http/server.ts";

const kv = await Deno.openKv();

interface User {
  id: string;
  name: string;
  email: string;
  role: string;
  department: string;
  status: string;
  createdAt: string;
  tags: string[];
}

// Seed some sample data
async function seedData() {
  const users: User[] = [
    { id: "1", name: "Alice Johnson", email: "alice@example.com", role: "admin", department: "engineering", status: "active", createdAt: "2024-01-15", tags: ["lead", "senior"] },
    { id: "2", name: "Bob Smith", email: "bob@example.com", role: "developer", department: "engineering", status: "active", createdAt: "2024-02-20", tags: ["junior"] },
    { id: "3", name: "Carol White", email: "carol@example.com", role: "designer", department: "design", status: "active", createdAt: "2024-03-10", tags: ["senior", "ux"] },
    { id: "4", name: "Dave Brown", email: "dave@example.com", role: "developer", department: "engineering", status: "inactive", createdAt: "2024-01-05", tags: ["senior", "backend"] },
    { id: "5", name: "Eve Davis", email: "eve@example.com", role: "manager", department: "product", status: "active", createdAt: "2024-04-01", tags: ["lead"] },
  ];

  for (const user of users) {
    // Primary key
    await kv.set(["users", user.id], user);

    // Secondary indexes for efficient lookups
    await kv.set(["users", user.id, "role", user.role], user);
    await kv.set(["users", user.id, "department", user.department], user);
    await kv.set(["users", user.id, "status", user.status], user);

    // Index by role
    await kv.set(["users_by_role", user.role, user.id], user);

    // Index by department
    await kv.set(["users_by_department", user.department, user.id], user);

    // Index by status
    await kv.set(["users_by_status", user.status, user.id], user);

    // Composite index: department + role
    await kv.set(["users_by_dept_role", user.department, user.role, user.id], user);

    // Index by tags
    for (const tag of user.tags) {
      await kv.set(["users_by_tag", tag, user.id], user);
    }
  }
}

// Build dynamic KV key from filter parameters
function buildKvKey(params: Record<string, string>): Deno.KvKey {
  const { id, role, department, status, tag } = params;

  // Direct user lookup by ID
  if (id && !role && !department && !status && !tag) {
    return ["users", id];
  }

  // Lookup by ID with specific filter
  if (id && role) {
    return ["users", id, "role", role];
  }
  if (id && department) {
    return ["users", id, "department", department];
  }
  if (id && status) {
    return ["users", id, "status", status];
  }

  // Composite index: department + role
  if (department && role) {
    return ["users_by_dept_role", department, role];
  }

  // Single index lookups
  if (role) {
    return ["users_by_role", role];
  }
  if (department) {
    return ["users_by_department", department];
  }
  if (status) {
    return ["users_by_status", status];
  }
  if (tag) {
    return ["users_by_tag", tag];
  }

  // Default: list all users
  return ["users"];
}

// Determine if we should do a single get or a list prefix scan
function isSingleLookup(params: Record<string, string>): boolean {
  const { id, role, department, status, tag } = params;
  // Single lookup when we have a full specific key
  if (id && !role && !department && !status && !tag) return true;
  if (id && role) return true;
  if (id && department) return true;
  if (id && status) return true;
  return false;
}

// Search with flexible filters including post-filter for criteria not covered by indexes
async function searchUsers(params: Record<string, string>): Promise<User[]> {
  const key = buildKvKey(params);
  const results: User[] = [];

  if (isSingleLookup(params)) {
    const entry = await kv.get<User>(key);
    if (entry.value) {
      results.push(entry.value);
    }
  } else {
    const iter = kv.list<User>({ prefix: key });
    for await (const entry of iter) {
      if (entry.value) {
        results.push(entry.value);
      }
    }
  }

  // Post-filter for additional criteria not covered by the index
  let filtered = results;

  if (params.name) {
    const nameQuery = params.name.toLowerCase();
    filtered = filtered.filter(u => u.name.toLowerCase().includes(nameQuery));
  }

  if (params.email) {
    const emailQuery = params.email.toLowerCase();
    filtered = filtered.filter(u => u.email.toLowerCase().includes(emailQuery));
  }

  // If we used a single-dimension index but also have other filters
  if (!isSingleLookup(params)) {
    if (params.role && params.department && !params.tag) {
      // Already handled by composite index
    } else {
      if (params.status && !key.includes("status")) {
        filtered = filtered.filter(u => u.status === params.status);
      }
      if (params.role && !JSON.stringify(key).includes(params.role)) {
        filtered = filtered.filter(u => u.role === params.role);
      }
      if (params.department && !JSON.stringify(key).includes(params.department)) {
        filtered = filtered.filter(u => u.department === params.department);
      }
    }
  }

  // Sorting
  if (params.sort) {
    const sortField = params.sort as keyof User;
    const order = params.order === "desc" ? -1 : 1;
    filtered.sort((a, b) => {
      const aVal = String(a[sortField] || "");
      const bVal = String(b[sortField] || "");
      return aVal.localeCompare(bVal) * order;
    });
  }

  // Pagination
  if (params.limit) {
    const limit = parseInt(params.limit, 10);
    const offset = parseInt(params.offset || "0", 10);
    filtered = filtered.slice(offset, offset + limit);
  }

  return filtered;
}

// Create or update a user with all indexes
async function upsertUser(user: User): Promise<void> {
  // Delete old indexes if user exists
  const existing = await kv.get<User>(["users", user.id]);
  if (existing.value) {
    await deleteUserIndexes(existing.value);
  }

  const atomic = kv.atomic();

  // Primary key
  atomic.set(["users", user.id], user);

  // Secondary indexes
  atomic.set(["users", user.id, "role", user.role], user);
  atomic.set(["users", user.id, "department", user.department], user);
  atomic.set(["users", user.id, "status", user.status], user);
  atomic.set(["users_by_role", user.role, user.id], user);
  atomic.set(["users_by_department", user.department, user.id], user);
  atomic.set(["users_by_status", user.status, user.id], user);
  atomic.set(["users_by_dept_role", user.department, user.role, user.id], user);

  for (const tag of user.tags) {
    atomic.set(["users_by_tag", tag, user.id], user);
  }

  await atomic.commit();
}

async function deleteUserIndexes(user: User): Promise<void> {
  const atomic = kv.atomic();

  atomic.delete(["users", user.id]);
  atomic.delete(["users", user.id, "role", user.role]);
  atomic.delete(["users", user.id, "department", user.department]);
  atomic.delete(["users", user.id, "status", user.status]);
  atomic.delete(["users_by_role", user.role, user.id]);
  atomic.delete(["users_by_department", user.department, user.id]);
  atomic.delete(["users_by_status", user.status, user.id]);
  atomic.delete(["users_by_dept_role", user.department, user.role, user.id]);

  for (const tag of user.tags) {
    atomic.delete(["users_by_tag", tag, user.id]);
  }

  await atomic.commit();
}

async function deleteUser(id: string): Promise<boolean> {
  const existing = await kv.get<User>(["users", id]);
  if (!existing.value) return false;
  await deleteUserIndexes(existing.value);
  return true;
}

function jsonResponse(data: unknown, status = 200): Response {
  return new Response(JSON.stringify(data, null, 2), {
    status,
    headers: {
      "Content-Type": "application/json",
      "Access-Control-Allow-Origin": "*",
      "Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
      "Access-Control-Allow-Headers": "Content-Type",
    },
  });
}

function errorResponse(message: string, status = 400): Response {
  return jsonResponse({ error: message }, status);
}

